using System;

class Program {
    static void Main() {
        int x = 10;
        if (x > 5) {
            Console.WriteLine("big");
        } else {
            Console.WriteLine("small");
        }
    }
}

using System;

class Program {
    static void Main() {
        int score = 85;
        if (score >= 90) Console.WriteLine("A");
        else if (score >= 80) Console.WriteLine("B");
        else if (score >= 70) Console.WriteLine("C");
        else Console.WriteLine("F");
    }
}

using System;

class Program {
    static void Main() {
        int n = 7;
        string kind = n % 2 == 0 ? "even" : "odd";
        Console.WriteLine($"{n} is {kind}");
    }
}

using System;

class Program {
    static void Main() {
        int day = 3;
        switch (day) {
            case 1: Console.WriteLine("Monday");    break;
            case 2: Console.WriteLine("Tuesday");   break;
            case 3: Console.WriteLine("Wednesday"); break;
            case 4: Console.WriteLine("Thursday");  break;
            case 5: Console.WriteLine("Friday");    break;
            default: Console.WriteLine("Weekend");  break;
        }
    }
}

using System;

class Program {
    static void Main() {
        for (int i = 1; i <= 5; i++) {
            string label = i switch {
                1 => "one",
                2 => "two",
                3 => "three",
                _ => "other"
            };
            Console.WriteLine(label);
        }
    }
}

using System;

class Program {
    static void Main() {
        int age = 20;
        bool hasId = true;
        Console.WriteLine(age >= 18 && hasId);
        Console.WriteLine(age < 18 || hasId);
        Console.WriteLine(!hasId);
    }
}

using System;

class Program {
    static void Main() {
        string maybeNull = null;
        string result = maybeNull ?? "default value";
        Console.WriteLine(result);

        int? length = maybeNull?.Length;
        Console.WriteLine(length ?? -1);
    }
}

using System;

class Program {
    static void Main() {
        object obj = 42;
        if (obj is int n) {
            Console.WriteLine($"integer: {n * 2}");
        } else if (obj is string s) {
            Console.WriteLine($"string: {s}");
        }
    }
}
